function sanitize(str, maxLen) {
  return String(str || "")
    .replace(/[\/\\:*?"<>|\r\n]/g, "_")
    .replace(/\s+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_+|_+$/g, "")
    .substring(0, maxLen || 60);
}

function stripKnownSubfolders(path) {
