    return {
      index: idx + 1,
      fileName: j._fileName || j.sourceFileName || j.name || j.filename || 'Dokument',
      filePath: j._filePath || j.sourceFilePath || j.nc_download_path || j.path || '',
      extractionOk: ok,
      extractedLength: j.extractedLength || text.length,
      extractionError: ok ? '' : (j.extractionError || 'Kein verwertbarer Text extrahiert'),
      text: ok ? text : ''
