if (wasTruncated) {
  combined += '\n\n[Hinweis: Originaldokumenttext wurde wegen Tokenlimit gekürzt.]';
}

let status = 'failed';
if (items.some(i => i.json?._noDocumentsFound) || documentCount === 0) {
  status = 'missing_documents';
} else if (extractedDocs.length > 0 && failedDocs.length === 0) {
  status = 'ok';
} else if (extractedDocs.length > 0) {
  status = 'partial';
}

