// Sortierung nach sachlicher ALLRIS-Reihenfolge:
// 1. Jahr aus Vorgangsnummer
// 2. Hauptnummer aus Vorgangsnummer
// 3. Folgenummer nach Bindestrich, z. B. 2026/196-01
// 4. volfdnr numerisch
// 5. firstseen als letzter Fallback
// 6. vorgangKey lexikografisch

function safe(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}

function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}

function parseVorgangsnummer(v) {
  const s = safe(v);
  const m = s.match(/^(\d{4})\/(\d+)(?:-(\d+))?/);
  if (!m) return { year: Infinity, main: Infinity, sub: 0 };
  return {
    year: parseInt(m[1], 10),
    main: parseInt(m[2], 10),
    sub: m[3] ? parseInt(m[3], 10) : 0
  };
}

const items = $input.all();

items.sort((a, b) => {
  const ja = a.json || {};
  const jb = b.json || {};

  const na = parseVorgangsnummer(ja.vorgangsnummer);
  const nb = parseVorgangsnummer(jb.vorgangsnummer);

  if (na.year !== nb.year) return na.year - nb.year;
  if (na.main !== nb.main) return na.main - nb.main;
  if (na.sub !== nb.sub) return na.sub - nb.sub;

  const va = parseVolfdnr(ja.volfdnr);
  const vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;

  const fa = parseDate(ja.firstseen);
  const fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;

  return safe(ja.vorgangKey).localeCompare(safe(jb.vorgangKey));
});

return items;

// Prüft, ob die veröffentlichungsnahen Kerntexte tatsächlich vorhanden sind.
const j = $input.item.json || {};
const errors = Array.isArray(j.contentValidationErrors)
